// Find leads sent 3+ days ago with no reply and no previous follow-up
const now = new Date();
const threeDaysAgo = new Date(now.getTime() - 3 * 24 * 60 * 60 * 1000);
const sevenDaysAfter = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const candidates = $input.all().filter(item => {
  const lead = item.json;

  // Must have been sent
  if (lead.Status !== 'Sent' && lead.Status !== 'Follow-up Sent') return false;

  // Must not have bounced
  if (lead.Bounced === 'TRUE' || lead.Bounced === true) return false;

  // Must not have replied
  if (lead.Replied === 'TRUE' || lead.Replied === true) return false;

  // Sent between 3 and 7 days ago (not too old, not too fresh)
  const sentDate = new Date(lead['Sent At'] || lead.sentAt || lead.SentDate);
  if (isNaN(sentDate.getTime())) return false;
  if (sentDate > threeDaysAgo) return false;  // Too recent, wait 3 days

  // If already had a follow-up, only follow up once more (check follow-up count)
  const followUpCount = parseInt(lead.FollowUpCount || '0');
  if (followUpCount >= 2) return false;  // Max 2 follow-ups

  return true;
});

// Classify each candidate
return candidates.map(item => {
  const lead = item.json;
  const opened = lead.Opened === 'TRUE' || lead.Opened === true;
  const clicked = lead.Clicked === 'TRUE' || lead.Clicked === true;
  const followUpCount = parseInt(lead.FollowUpCount || '0');

  let followUpType = 'no-engagement';
  if (clicked) followUpType = 'clicked-no-reply';
  else if (opened) followUpType = 'opened-no-reply';

  return {
    json: {
      ...lead,
      followUpType,
      followUpCount: followUpCount + 1
    }
  };
});

// Gentle nudge for leads who opened but didn't reply
const lead = $input.item.json;

const followUpSubject = 'Re: ' + lead['Subject Line'];
const followUpBody = 'Hi ' + (lead.Name || lead.name) + ',\n\n' +
  'I noticed you opened my previous email — just wanted to make sure it didn\'t get lost in the shuffle.\n\n' +
  'Would a quick 5-minute call this Thursday or Friday work for you?\n\n' +
  'Best,\n[Your Name]';

return {
  json: {
    ...lead,
    followUpSubject,
    followUpBody,
    followUpType: 'opened-no-reply'
  }
};

// Warm follow-up for leads who clicked a link but didn't reply
const lead = $input.item.json;

const followUpSubject = 'Following up — ' + (lead.Company || lead.company);
const followUpBody = 'Hi ' + (lead.Name || lead.name) + ',\n\n' +
  'Saw you checked out the link I shared — glad it caught your interest!\n\n' +
  'I have a few more insights specific to ' + (lead.Company || lead.company) +
  ' that I think you\'d find valuable. Are you open to a quick chat next week?\n\n' +
  'Best,\n[Your Name]';

return {
  json: {
    ...lead,
    followUpSubject,
    followUpBody,
    followUpType: 'clicked-no-reply'
  }
};

// Different approach for leads who never engaged
const lead = $input.item.json;

const followUpSubject = 'Different angle for ' + (lead.Company || lead.company);
const followUpBody = 'Hi ' + (lead.Name || lead.name) + ',\n\n' +
  'I know you\'re busy, so I\'ll keep this short — different angle than my last message.\n\n' +
  'We recently helped a company similar to ' + (lead.Company || lead.company) +
  ' achieve [specific result]. Thought it might be relevant to what you\'re working on.\n\n' +
  'Worth a 10-minute exploration?\n\n' +
  'Best,\n[Your Name]';

return {
  json: {
    ...lead,
    followUpSubject,
    followUpBody,
    followUpType: 'no-engagement'
  }
};
